        return f"Available voices ({len(result)}):\n" + "\n".join(result)
    except Exception as e:
        return f"Error listing voices: {str(e)}"


def list_models() -> str:
    """List all available ElevenLabs TTS models."""
    try:
        import requests
        api_key = get_var("ELEVENLABS_API_KEY")
        if not api_key:
            return "Error: ELEVENLABS_API_KEY is not configured. Please set it in Environment Variables settings."

        headers = {
            "xi-api-key": api_key,
            "Content-Type": "application/json"
        }
        resp = requests.get("https://api.elevenlabs.io/v1/models", headers=headers, timeout=30)
        if resp.status_code != 200:
            return f"Error ({resp.status_code}): {resp.text}"

        models = resp.json()
        result = []
        for m in models:
            can_tts = m.get("can_do_text_to_speech", False)
            if can_tts:
                result.append(f"- **{m['name']}** (ID: {m['model_id']}) — {m.get('description', 'No description')}")

        if not result:
            return "No TTS models found."
        return f"Available TTS models ({len(result)}):\n" + "\n".join(result)
    except Exception as e:
        return f"Error listing models: {str(e)}"


def generate_speech(text: str, voice_name: str, model_id: str = "eleven_multilingual_v2", stability: float = 0.5, similarity_boost: float = 0.75, style: float = 0.0) -> str:
    """Generate speech audio from text using ElevenLabs TTS API.

    Args:
        text: The text to convert to speech.
        voice_name: The name of the voice to use (e.g. 'Rachel', 'Adam'). Will search available voices by name.
        model_id: The model ID to use. Default is 'eleven_multilingual_v2'. Use 'eleven_monolingual_v1' for English-only.
        stability: Voice stability (0.0 to 1.0). Lower = more expressive, higher = more consistent. Default 0.5.
        similarity_boost: Voice clarity/similarity boost (0.0 to 1.0). Default 0.75.
        style: Style exaggeration (0.0 to 1.0). Higher values add more style. Default 0.0. Only works with v2 models.
    """
    try:
        import requests
        api_key = get_var("ELEVENLABS_API_KEY")
        if not api_key:
            return "Error: ELEVENLABS_API_KEY is not configured. Please set it in Environment Variables settings."

        if not text or not text.strip():
            return "Error: Text cannot be empty."
        if not voice_name or not voice_name.strip():
            return "Error: Voice name is required. Use list_voices() to see available options."

        headers = {
            "xi-api-key": api_key,
            "Content-Type": "application/json"
        }

        # Look up voice by name
        resp = requests.get("https://api.elevenlabs.io/v1/voices", headers=headers, timeout=30)
        if resp.status_code != 200:
            return f"Error fetching voices ({resp.status_code}): {resp.text}"

        voices = resp.json().get("voices", [])
        voice_id = None
        matched_name = None

        # Try exact match first (case-insensitive)
        for v in voices:
            if v["name"].lower() == voice_name.lower().strip():
                voice_id = v["voice_id"]
                matched_name = v["name"]
                break

        # Try partial match
        if not voice_id:
            for v in voices:
                if voice_name.lower().strip() in v["name"].lower():
                    voice_id = v["voice_id"]
                    matched_name = v["name"]
                    break

        # Check if voice_name is already an ID
        if not voice_id:
            for v in voices:
                if v["voice_id"] == voice_name.strip():
                    voice_id = v["voice_id"]
                    matched_name = v["name"]
                    break

        if not voice_id:
            available = ", ".join([v["name"] for v in voices[:20]])
            return f"Error: Voice '{voice_name}' not found. Available voices include: {available}"

        # Generate speech
        url = f"https://api.elevenlabs.io/v1/text-to-speech/{voice_id}"
        payload = {
            "text": text,
            "model_id": model_id,
            "voice_settings": {
                "stability": max(0.0, min(1.0, stability)),
                "similarity_boost": max(0.0, min(1.0, similarity_boost)),
                "style": max(0.0, min(1.0, style)),
                "use_speaker_boost": True
            }
        }

        resp = requests.post(url, headers=headers, json=payload, timeout=120)
        if resp.status_code != 200:
            return f"Error generating speech ({resp.status_code}): {resp.text}"

        # Save audio file
        timestamp = int(time.time())
        safe_voice = matched_name.replace(' ', '_').lower()
        filename = f"elevenlabs_{safe_voice}_{timestamp}.mp3"
        filepath = os.path.join(os.getcwd(), filename)

        with open(filepath, "wb") as f:
            f.write(resp.content)

        file_size_kb = len(resp.content) / 1024
        text_preview = text[:80] + "..." if len(text) > 80 else text

        return (
            f"Speech generated successfully!\n"
            f"- **Voice**: {matched_name}\n"
            f"- **Model**: {model_id}\n"
            f"- **Text**: \"{text_preview}\"\n"
            f"- **File**: {filepath}\n"
            f"- **Size**: {file_size_kb:.1f} KB"
        )
    except Exception as e:
        return f"Error generating speech: {str(e)}"
